SELECT users.user_id, users.username, users.email, logs.action, logs.log_date
FROM users
JOIN logs ON users.user_id = logs.user_id;

SELECT AVG(market_cap) 
FROM stocks 
WHERE ticker_symbol LIKE 'D%';

SELECT *
FROM stocks
WHERE sector = 'Technology';

SELECT COUNT(DISTINCT t.user_id) AS count_users
FROM transactions t
INNER JOIN alerts a ON t.user_id = a.user_id AND t.stock_id = a.stock_id;

SELECT AVG(volume) as average_daily_volume
FROM market_data
WHERE stock_id = (SELECT stock_id FROM stocks WHERE ticker_symbol = 'AAPL');

SELECT stocks.ticker_symbol, users.username, users.email
FROM stocks
JOIN users ON stocks.stock_id = users.user_id;

SELECT setting_name 
FROM settings 
WHERE user_id = (SELECT user_id FROM users WHERE username = 'bob.williams');
